mapper.select:
SELECT R.REQUEST_ID AS requestId, R.BUSINESS_ID AS businessId, R.LOCATION_ID AS locationId, R.ADMIN_USER_ID AS adminUserId, R.COUPON_NAME AS couponName, R.COUPON_DESCRIPTION AS couponDescription, R.PRICE_POINT AS pricePoint, R.STOCK AS stock, R.TARGET_STATUS AS targetStatus, R.REQUEST_STATUS AS requestStatus, R.REQUEST_VERSION AS requestVersion, R.LAST_HOLD_REASON AS lastHoldReason, R.APPROVED_REWARD_ITEM_ID AS approvedRewardItemId, R.REQUESTED_AT AS requestedAt, R.RESPONDED_AT AS respondedAt, R.CREATED_AT AS createdAt, R.UPDATED_AT AS updatedAt, B.USER_ID AS businessUserId, B.BUSINESS_NAME AS businessName, L.NAME AS locationName, L.ADDRESS AS locationAddress, AU.NICKNAME AS adminNickname FROM LQ_BUSINESS_COUPON_REQUEST R INNER JOIN LQ_BUSINESS B ON B.BUSINESS_ID = R.BUSINESS_ID INNER JOIN LQ_LOCATION L ON L.LOCATION_ID = R.LOCATION_ID LEFT JOIN LQ_USER AU ON AU.USER_ID = R.ADMIN_USER_ID
AND R.REQUEST_STATUS = #{requestStatus}
AND R.BUSINESS_ID = #{businessId}
AND R.LOCATION_ID = #{locationId}
AND R.ADMIN_USER_ID = #{adminUserId}
AND B.USER_ID = #{businessUserId}
AND ( R.COUPON_NAME LIKE '%' || #{keyword} || '%' OR B.BUSINESS_NAME LIKE '%' || #{keyword} || '%' OR L.NAME LIKE '%' || #{keyword} || '%' )
ORDER BY R.REQUEST_ID DESC
